const express = require('express');
const elasticsearch = require('elasticsearch');

const app = express();
const client = new elasticsearch.Client({
  host: 'http://localhost:9200',
});

app.post('/search', (req, res) => {
  const query = req.body.query;
  const filters = req.body.filters;
  const scoringScript = req.body.scoringScript;

  // Build the Elasticsearch Query DSL
  const esQuery = {
    bool: {
      must: [
        {
          query_string: {
            query,
            fields: ['title^3', 'content'],
          },
        },
      ],
      filter: filters.map((filter) => ({ term: { [filter]: true } })),
    },
  };

  // Use the script_score query with user-provided script logic to customize search relevance
  if (scoringScript) {
    esQuery.bool.must.push({
      script_score: {
        script: scoringScript,
      },
    });
  }

  client.search(esQuery).then((response) => {
    res.json(response);
  }).catch((error) => {
    console.log(error);
    res.status(500).send('Error searching Elasticsearch');
  });
});